 52→@Slf4j
 53→@Configuration(proxyBeanMethods = false)
 54→public class MattermostUserSyncTask {
 55→
 56→    @Resource
 57→    private MattermostUserFeignClient mattermostUserFeignClient;
 58→
 59→    @Resource
 60→    private MattermostGroupFeignClient mattermostGroupFeignClient;
 61→
 62→    @Resource
 63→    private IUserProjectService userProjectService;
 64→
 65→    @Resource
 66→    private IUserProjectTeamRelService userProjectTeamRelService;
 67→
 68→    @Resource
 69→    private IUserTeamService userTeamService;
 70→
 71→    @Resource
 72→    private IUserTeamUserRelService userTeamUserRelService;
 73→
 74→    @Resource
 75→    private IApitableGrpcClientService apitableGrpcClientService;
 76→
 77→    @Resource
 78→    private UserTeamUpdateManager userTeamUpdateManager;
 79→
 80→    @Resource
 81→    private AffineHttpClientService affineHttpClientService;
 82→
 83→    @Resource
 84→    private IViewUserTeamRelService viewUserTeamRelService;
 85→
 86→    @Resource
 87→    private RabbitMqSender rabbitMqSender;
 88→
 89→    @Resource
 90→    private MattermostProperties mattermostProperties;
 91→
 92→    @Resource
 93→    private ConstProperties constProperties;
 94→
 95→    @Resource
 96→    private RedisTemplate<String, String> redisTemplate;
 97→
 98→    @Resource
 99→    private IAuthService authService;
100→
101→    @Value("${mm-test-only-tag:false}")
102→    private boolean mmTestOnlyOnlyTag;
103→
104→    @Value("${mm-test-filter-tag:false}")
105→    private boolean mmTestFilterTag;
106→
107→    private static  final Long SPEC_OPERATOR = -1L;
108→
109→
110→    @Scheduled(cron = "0 0/1 * * * ?")
111→    public void schedulerJobTask() {
112→
113→        log.info("Scheduler task started");
114→
115→        boolean internalNetwork = constProperties.isInternalNetwork();
116→        if(!internalNetwork && !mmTestOnlyOnlyTag)
117→            return;
118→
119→        boolean mirror = constProperties.isMirror();
120→        if(mirror)
121→            return;
122→
123→        log.info("Scheduler task initiated");
124→
125→
126→        Long operator = -1L;
127→
128→        List<UserSimpleInfoVo> allExistUsers = apitableGrpcClientService.getAllExistUsers(operator);
129→        Map<String, Long> allUserEmailMap = new HashMap<>();
130→        Map<Long, String> allUserIdMap = new HashMap<>();
131→        Map<String, UserSimpleInfoVo> existUserMap = allExistUsers.stream().filter(x->StringUtils.isNotBlank(x.getEmail()) && x.getEmail().endsWith("@yottastudios.com")).
132→                collect(Collectors.toMap(UserSimpleInfoVo::getEmail,Function.identity(),(v1,v2)->v2));
133→        Set<String> departUserEmails = new HashSet<>();
134→        Set<String> recoverUserEmails = new HashSet<>();
135→        List<Long> updateMmSyncUserIds = new ArrayList<>();
136→        List<Long> inTeamUserIds = new ArrayList<>();
137→
138→        //手动添加用户
139→        List<String> manualUserEmails = new ArrayList<>(allExistUsers.stream().filter(x -> StringUtils.isNotBlank(x.getEmail()) && !x.getIsMmSync()).
140→                map(UserSimpleInfoVo::getEmail).toList());
141→        Map<Long, UserSimpleInfoVo> manualUserMap = allExistUsers.stream().filter(x->StringUtils.isNotBlank(x.getEmail()) && !x.getIsMmSync()).
142→                collect(Collectors.toMap(UserSimpleInfoVo::getId,Function.identity()));
143→        List<Long> manualUserIds = new ArrayList<>(allExistUsers.stream().filter(x -> StringUtils.isNotBlank(x.getEmail()) && !x.getIsMmSync()).
144→                map(UserSimpleInfoVo::getId).toList());
145→        log.info("manualUserEmails1 size: {}", manualUserEmails.size());
146→
147→
148→
149→        List<UserProjectEntity> mmProjectList = userProjectService.list().stream().filter(x -> StringUtils.isNotBlank(x.getMattermostId())).toList();
150→        if(CollectionUtils.isEmpty(mmProjectList)) return;
151→
152→        for (UserProjectEntity project : mmProjectList) {
153→
154→            // false不代表接口没变化... Boolean cacheUpdateKey=false;
155→
156→            Long projectId = project.getId();
157→
158→            List<MattermostUserResp> mmUserList = getMMUserList(project.getMattermostId());
159→            //过滤掉并过滤出要删除的用户
160→
161→            Set<String> contractorUserEmails = new HashSet<>();
162→            List<MattermostGroupResp> mmUsersWithTeam = getUsersWithTeam(project.getMattermostId());
163→            List<MattermostGroupResp> contractorTeam =
164→                    mmUsersWithTeam.stream().filter(t -> t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();
165→            if(CollectionUtils.isNotEmpty(contractorTeam)){
166→                contractorTeam.forEach(ct->{
167→                    List<MattermostGroupResp.UserSimpleResp> users = ct.getUsers();
168→                    if(CollectionUtils.isNotEmpty(users))
169→                        users.forEach(user-> contractorUserEmails.add(user.getEmail()));
170→                });
171→            }
172→            if(CollectionUtils.isNotEmpty(contractorUserEmails)){
173→                mmUserList = mmUserList.stream().filter(x->!contractorUserEmails.contains(x.getEmail())).toList();
174→                departUserEmails.addAll(contractorUserEmails);
175→            }
176→            mmUsersWithTeam=mmUsersWithTeam.stream().filter(t -> !t.getDisplaygroupname().toLowerCase().startsWith("expat")).toList();
177→
178→            Map<String, MattermostUserResp> mmUserMap = mmUserList.stream().collect(Collectors.toMap(MattermostUserResp::getEmail, Function.identity()));
179→            //add User
180→            mmUserMap.forEach((k, v) -> {
181→                if(!Validator.isEmail(k)) return;
182→                if(allUserEmailMap.containsKey(k)) return;
183→                if (existUserMap.containsKey(k)){
184→                    UserSimpleInfoVo userSimpleInfoVo = existUserMap.get(k);
185→                    allUserEmailMap.put(k, userSimpleInfoVo.getId());
186→                    allUserIdMap.put(userSimpleInfoVo.getId(),k);
187→                    if(UserStatusEnum.DISABLE.getValue().equals(userSimpleInfoVo.getStatus())){
188→                        recoverUserEmails.add(k);
189→                    } else if(manualUserEmails.contains(k)){
190→                        log.info("manualUserEmails updateIn");
191→                        updateMmSyncUserIds.add(userSimpleInfoVo.getId());
192→                        manualUserEmails.remove(k);
193→                        manualUserMap.remove(userSimpleInfoVo.getId());
194→                        manualUserIds.remove(userSimpleInfoVo.getId());
195→                    }
196→
197→                } else {
198→                    Long registerId = null;
199→                    try{
200→                        registerId = authService.register(v.getEmail(), StringUtils.isNotBlank(v.getNickname()) ? v.getNickname() : v.getUsername(), RandomExtendUtil.randomString(8),true);
201→
202→                    }catch (Exception e){
203→                        log.error("schedulerJobTask register error : {}",k,e);
204→                    }
205→                    if(null!=registerId){
206→                        allUserEmailMap.put(k,registerId);
207→                        allUserIdMap.put(registerId,k);
208→                    }
209→                }
210→            });
211→
212→
213→            Map<String, UserTeamEntity> teamMMMap = new HashMap<>();
214→            Map<Long, List<UserTeamUserRelEntity>> teamUserRelGroup = new HashMap<>();
215→            List<UserTeamEntity> errorTeamList = new ArrayList<>();
216→            Long commonRelTeamId = null;
217→            List<UserProjectTeamRelEntity> teamRelList = userProjectTeamRelService.listByProjectId(projectId);
218→            if(CollectionUtils.isNotEmpty(teamRelList)){
219→                UserProjectTeamRelEntity commonRel = teamRelList.stream().filter(x -> BinaryOperationEnum.ON.getValue().equals(x.getIsCommon())).findFirst().orElse(null);
220→                if(null!=commonRel)
221→                    commonRelTeamId =commonRel.getTeamId();
222→
223→                List<Long> teamIds = teamRelList.stream().map(UserProjectTeamRelEntity::getTeamId).toList();
224→                List<UserTeamEntity> userTeamList = userTeamService.listByIds(teamIds);
225→
226→                teamMMMap = userTeamList.stream().filter(x->StringUtils.isNotBlank(x.getMattermostId())).collect(Collectors.toMap(UserTeamEntity::getMattermostId, Function.identity()));
227→                Long finalCommonRelTeamId = commonRelTeamId;
228→                errorTeamList = userTeamList.stream().filter(x -> (StringUtils.isBlank(x.getMattermostId()) && !x.getId().equals(finalCommonRelTeamId))
229→                        && TeamDataSourceType.MATTERMOST.getId().equals(x.getDataSource())).toList();
230→                List<UserTeamUserRelEntity> userTeamRelList = userTeamUserRelService.listInTeamIds(teamIds);
231→                if(CollectionUtils.isNotEmpty(userTeamList)){
232→                    teamUserRelGroup = userTeamRelList.stream().collect(Collectors.groupingBy(UserTeamUserRelEntity::getTeamId));
233→                }
234→            }
235→
236→            mmUsersWithTeam=mmUsersWithTeam.stream().filter(x->StringUtils.isNotBlank(x.getGroupid())).toList();
237→            for (MattermostGroupResp mmTeam : mmUsersWithTeam) {
238→                String groupId = mmTeam.getGroupid();
239→                Long teamId;
240→                if(teamMMMap.containsKey(groupId)){
241→                    UserTeamEntity userTeamEntity = teamMMMap.get(groupId);
242→                    teamId=userTeamEntity.getId();
243→                    if(!userTeamEntity.getTeamName().equals(mmTeam.getDisplaygroupname())){
244→                        //update team name
245→                        userTeamEntity.setTeamName(mmTeam.getDisplaygroupname());
246→                        userTeamService.updateById(userTeamEntity);
247→                    }
248→                    //team user set
249→                    List<MattermostGroupResp.UserSimpleResp> mmTeamUsers = mmTeam.getUsers();
250→                    List<String> mmUserEmail = mmTeamUsers.stream().map(MattermostGroupResp.UserSimpleResp::getEmail).toList();
251→                    List<Long> mmUserIds = new ArrayList<>();
252→                    for (String e : mmUserEmail) {
253→                        if (allUserEmailMap.containsKey(e))
254→                            mmUserIds.add(allUserEmailMap.get(e));
255→                    }
256→                    inTeamUserIds.addAll(mmUserIds);
257→                    List<UserTeamUserRelEntity> curUserRelList = teamUserRelGroup.get(teamId);
258→
259→                    List<Long> addUserIds;
260→                    List<Long> updateUserIds = new ArrayList<>();
261→                    List<Long> delUserIds = new ArrayList<>();
262→                    if(CollectionUtils.isNotEmpty(curUserRelList)){
263→                        List<Long> curUserRelIds = curUserRelList.stream().map(UserTeamUserRelEntity::getUserId).toList();
264→                        addUserIds = mmUserIds.stream().filter(x->!curUserRelIds.contains(x)).toList();
265→                        curUserRelList.forEach(x->{
266→                            if(!mmUserIds.contains(x.getUserId())){
267→                                UserSimpleInfoVo userSimpleInfoVo = manualUserMap.get(x.getUserId());
268→                                if(null==userSimpleInfoVo){
269→                                    delUserIds.add(x.getUserId());
270→                                }
271→                            }
272→                        });
273→                        curUserRelList.forEach(x->{
274→                            if(mmUserIds.contains(x.getUserId()))
275→                                updateUserIds.add(x.getUserId());
276→                        });
277→                    }else{
278→                        addUserIds=mmUserIds;
279→                    }
280→                    //add user
281→                    if(CollectionUtils.isNotEmpty(addUserIds)){
282→
283→                        List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
284→                        addUserIds.forEach(u -> userRelEntities.add(UserTeamUserRelEntity.builder().teamId(teamId).userId(u).build()));
285→                        userTeamUserRelService.saveBatch(userRelEntities);
286→
287→                        UserTeamOperateMessage messageDto = new UserTeamOperateMessage(addUserIds, List.of(teamId), AioTeamOperateTypeEnum.ADD_USER.getValue(),SPEC_OPERATOR);
288→                        log.info("Sending object to exchange: {}, routeKey: {},message:{}", AIO_TEAM_OPERATE_EXCHANGE, AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
289→                        rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
290→                    }
291→
292→                    //delete user
293→                    if(CollectionUtils.isNotEmpty(delUserIds)){
294→                        userTeamUserRelService.delByTeamIdInUserIds(teamId,delUserIds);
295→                        UserTeamOperateMessage messageDto = new UserTeamOperateMessage(delUserIds, List.of(teamId), AioTeamOperateTypeEnum.DELETE_USER.getValue(),SPEC_OPERATOR);
296→                        rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
297→                    }
298→
299→                    if(CollectionUtils.isNotEmpty(updateUserIds)){
300→                        userTeamUserRelService.setInTeam(teamId,updateUserIds);
301→                    }
302→
303→                    //删除空组
304→                    if (CollectionUtils.isEmpty(addUserIds)) {
305→                        if (CollectionUtils.isEmpty(curUserRelList)) {
306→                            userTeamUserRelService.delByTeamId(teamId);
307→                            viewUserTeamRelService.delByTeamId(teamId);
308→                            userTeamUpdateManager.deleteTeam(teamId);
309→                        } else {
310→
311→                            if (CollectionUtils.isNotEmpty(delUserIds) ) {
312→                                //比较curUserRelList是先过滤出isMmSync的
313→                                int curSize=curUserRelList.size();
314→                                if(CollectionUtils.isNotEmpty(curUserRelList)){
315→                                    curSize = curUserRelList.stream().filter(x->!manualUserIds.contains(x.getUserId())).toList().size();
316→                                }
317→                                if(delUserIds.size() == curSize){
318→                                    userTeamUserRelService.delByTeamId(teamId);
319→                                    viewUserTeamRelService.delByTeamId(teamId);
320→                                    userTeamUpdateManager.deleteTeam(teamId);
321→                                }
322→
323→                            }
324→                        }
325→                    }
326→
327→                }else{
328→                    List<MattermostGroupResp.UserSimpleResp> mmTeamUsers = mmTeam.getUsers();
329→                    List<String> mmUserEmail = mmTeamUsers.stream().map(MattermostGroupResp.UserSimpleResp::getEmail).toList();
330→                    List<Long> mmUserIds = new ArrayList<>();
331→                    for (String e : mmUserEmail) {
332→                        if (allUserEmailMap.containsKey(e))
333→                            mmUserIds.add(allUserEmailMap.get(e));
334→                    }
335→                    if(CollectionUtils.isNotEmpty(mmUserIds)){
336→                        //add team
337→                        TeamInfoVo newTeam = userTeamUpdateManager.createTeamForSync(new TeamCreateRo(mmTeam.getDisplaygroupname(), projectId,groupId,BinaryOperationEnum.OFF.getValue(), TeamDataSourceType.MATTERMOST.getId()));
338→                        teamId = newTeam.getId();
339→
340→                        List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
341→                        mmUserIds.forEach(u -> userRelEntities.add(UserTeamUserRelEntity.builder().teamId(teamId).userId(u).build()));
342→                        userTeamUserRelService.saveBatch(userRelEntities);
343→
344→                        UserTeamOperateMessage messageDto = new UserTeamOperateMessage(mmUserIds, List.of(teamId), AioTeamOperateTypeEnum.ADD_USER.getValue(),SPEC_OPERATOR);
345→                        log.info("Sending object to exchange: {}, routeKey: {},message:{}", AIO_TEAM_OPERATE_EXCHANGE, AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
346→                        rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
347→                    }
348→
349→                }
350→
351→            }
352→
353→            //delete team
354→            if(!teamMMMap.isEmpty()){
355→                List<String> mmIds = mmUsersWithTeam.stream().map(MattermostGroupResp::getGroupid).toList();
356→                teamMMMap.forEach((k, v) -> {
357→                    if(!mmIds.contains(k)){
358→                        userTeamUserRelService.delByTeamId(v.getId());
359→                        viewUserTeamRelService.delByTeamId(v.getId());
360→                        userTeamUpdateManager.deleteTeam(v.getId());
361→                    }
362→                });
363→            }
364→            if(CollectionUtils.isNotEmpty(errorTeamList)){
365→                errorTeamList.forEach(team -> {
366→                    userTeamUserRelService.delByTeamId(team.getId());
367→                    viewUserTeamRelService.delByTeamId(team.getId());
368→                    userTeamUpdateManager.deleteTeam(team.getId());
369→                });
370→            }
371→
372→            //通用组特殊处理
373→            List<Long> allUserIds = inTeamUserIds.stream().distinct().toList();
374→            if(null==commonRelTeamId){
375→                //add team
376→                TeamInfoVo commonTeam = userTeamUpdateManager.createTeamForSync(new TeamCreateRo("全部成员", projectId,null,BinaryOperationEnum.ON.getValue(),TeamDataSourceType.MATTERMOST.getId()));
377→                commonRelTeamId = commonTeam.getId();
378→                //batch save
379→                List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
380→                for (Long u : allUserIds)
381→                    userRelEntities.add(UserTeamUserRelEntity.builder().teamId(commonRelTeamId).userId(u).build());
382→
383→                userTeamUserRelService.saveBatch(userRelEntities);
384→
385→            }else{
386→                List<UserTeamUserRelEntity> curUserRelList = teamUserRelGroup.get(commonRelTeamId);
387→                List<Long> addUserIds;
388→                List<Long> delUserIds = new ArrayList<>();
389→                if(CollectionUtils.isNotEmpty(curUserRelList)){
390→                    List<Long> curUserRelIds = curUserRelList.stream().map(UserTeamUserRelEntity::getUserId).toList();
391→                    addUserIds = allUserIds.stream().filter(x->!curUserRelIds.contains(x)).toList();
392→                    curUserRelList.forEach(x->{
393→                        if(!allUserIds.contains(x.getUserId())){
394→                            UserSimpleInfoVo userSimpleInfoVo = manualUserMap.get(x.getUserId());
395→                            if(null==userSimpleInfoVo){
396→                                delUserIds.add(x.getUserId());
397→                            }
398→                        }
399→                    });
400→                }else{
401→                    addUserIds=allUserIds;
402→                }
403→                //add user
404→                if(CollectionUtils.isNotEmpty(addUserIds)){
405→
406→                    List<UserTeamUserRelEntity> userRelEntities = new ArrayList<>();
407→                    for (Long u : addUserIds)
408→                        userRelEntities.add(UserTeamUserRelEntity.builder().teamId(commonRelTeamId).userId(u).build());
409→
410→                    userTeamUserRelService.saveBatch(userRelEntities);
411→
412→                    UserTeamOperateMessage messageDto = new UserTeamOperateMessage(addUserIds, List.of(commonRelTeamId), AioTeamOperateTypeEnum.ADD_USER.getValue(),SPEC_OPERATOR);
413→                    rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
414→                }
415→
416→                //delete user
417→                if(CollectionUtils.isNotEmpty(delUserIds)){
418→
419→                    userTeamUserRelService.delByTeamIdInUserIds(commonRelTeamId,delUserIds);
420→
421→                    UserTeamOperateMessage messageDto = new UserTeamOperateMessage(delUserIds, List.of(commonRelTeamId), AioTeamOperateTypeEnum.DELETE_USER.getValue(),SPEC_OPERATOR);
422→                    rabbitMqSender.directSend(AIO_TEAM_OPERATE_EXCHANGE,AIO_TEAM_OPERATE_KEY, JSONUtil.toJsonStr(messageDto));
423→
424→                }
425→            }
426→        }
427→
428→        //recover
429→        if(CollectionUtils.isNotEmpty(recoverUserEmails)){
430→            recoverUsers(new ArrayList<>(recoverUserEmails));
431→        }
432→
433→        //update
434→        //recover
435→        if(CollectionUtils.isNotEmpty(updateMmSyncUserIds)){
436→            log.info("updateMmSyncUserIds size: {}", updateMmSyncUserIds.size());
437→            apitableGrpcClientService.updateIsMmSyncSourceByUserIds(updateMmSyncUserIds,true);
438→        }
439→
440→        //team depart
441→        log.info("departUserEmails size: {}", departUserEmails.size());
442→        if(CollectionUtils.isNotEmpty(departUserEmails)){
443→            List<String> teamDepartUsers = allExistUsers.stream().filter(x -> departUserEmails.contains(x.getEmail()) && UserStatusEnum.NORMAL.getValue().equals(x.getStatus())
444→                    && !manualUserEmails.contains(x.getEmail())).
445→                    map(UserSimpleInfoVo::getEmail).toList();
446→            log.info("teamDepartUsers size: {}", teamDepartUsers.size());
447→            if(CollectionUtils.isNotEmpty(teamDepartUsers)){
448→                departUsers(teamDepartUsers);
449→            }
450→        }
451→
452→        //filterToDepart
453→        Set<String> allMMEmails = allUserEmailMap.keySet();
454→        List<String> filterToDepartEmails = allExistUsers.stream().filter(x -> !allMMEmails.contains(x.getEmail()) && UserStatusEnum.NORMAL.getValue().equals(x.getStatus())).
455→                    map(UserSimpleInfoVo::getEmail).toList();
456→        log.info("filterToDepartEmails size: {}", filterToDepartEmails.size());
457→
458→        Map<String, UserSimpleInfoVo> allUserEmailToUserMap = allExistUsers.stream()
459→                .filter(x -> StringUtils.isNotBlank(x.getEmail()))
460→                .collect(Collectors.toMap(
461→                        UserSimpleInfoVo::getEmail,
462→                        Function.identity(),
463→                        (v1, v2) -> v2
464→                ));
465→
466→        // 然后在过滤时使用
467→        if (CollectionUtils.isNotEmpty(filterToDepartEmails)) {
468→            filterToDepartEmails = filterToDepartEmails.stream()
469→                    .filter(x -> {
470→                        if (StringUtils.isBlank(x) || manualUserEmails.contains(x)) {
471→                            return false;
472→                        }
473→
474→                        UserSimpleInfoVo user = allUserEmailToUserMap.get(x);
475→                        if (user == null) {
476→                            log.warn("User email not found: {}", x);
477→                            return false;
478→                        }
479→
480→                        return UserStatusEnum.NORMAL.getValue().equals(user.getStatus());
481→                    })
482→                    .toList();
483→        }
484→
485→        log.info("filterToDepartEmails final size: {}", filterToDepartEmails.size());
486→        if(CollectionUtils.isNotEmpty(filterToDepartEmails)&&!mmTestFilterTag){
487→            departUsers(filterToDepartEmails);
488→        }
489→
