492→    private List<MattermostUserResp> getMMUserList(String projectId){
493→        List<MattermostUserResp> allUsers = new ArrayList<>();
494→        int page = 0;
495→        boolean hasMore = true;
496→        int batchSize =100;
497→
498→
499→        while (hasMore) {
500→            List<MattermostUserResp> mattermostUsers = mattermostUserFeignClient.getUsers(
501→                    "Bearer " + mattermostProperties.getReqToken(),
502→                    page, batchSize,
503→                    projectId,
504→                    null, null, null, null, null, null, null, null, null, null, null, null, null, null
505→            );
506→
507→            if (CollectionUtils.isEmpty(mattermostUsers) || mattermostUsers.size() < batchSize) {
508→                hasMore = false;
509→            }
510→
511→            allUsers.addAll(mattermostUsers);
512→            page++;
513→
514→        }
515→
516→        try{
517→            String cacheInfo = JSONUtil.toJsonStr(allUsers);
518→            String key = RedisConstants.getMMUserKey(projectId);
519→            long twoHoursInSeconds = 2 * 60 * 60;
520→            redisTemplate.opsForValue().set(key, cacheInfo, twoHoursInSeconds, TimeUnit.SECONDS);
521→        }catch (Exception e){
522→            log.error("MMUserList cache update error",e);
523→        }
524→
525→
526→        return allUsers;
527→    }
