16→@Service
17→@Slf4j
18→public class MattermostOAuthServiceImpl extends AbstractOAuthTemplate {
19→
20→    @Resource
21→    private MattermostOAuthFeign mattermostOAuthFeign;
22→
23→    @Resource
24→    private AuthProperties authProperties;
25→
26→    @Override
27→    protected String getOAuthBaseUrl() {
28→        return authProperties.getMattermostBrowserUrl() + "/oauth";
29→    }
30→
31→    @Override
32→    protected String getClientId() {
33→        return authProperties.getMattermostClientId();
34→    }
35→
36→    @Override
37→    protected String getClientSecret() {
38→        return authProperties.getMattermostClientSecret();
39→    }
40→
41→    @Override
42→    protected OAuthUserInfo retrieveOAuthUserInfo(String code, String clientId, String clientSecret, String redirectUri) {
43→        final String grantType = "authorization_code";
44→        MattermostAuthTokenResp authTokenResp = mattermostOAuthFeign.token(code, clientId, clientSecret, redirectUri, grantType);
45→        if (authTokenResp == null) {
46→            log.error("fetch mattermost token error");
47→            throw new BusinessException("failed to fetch mattermost token");
48→        }
49→
50→        String accessToken = authTokenResp.getAccessToken();
51→        ExceptionUtil.isNotBlank(accessToken, AuthException.UNAUTHORIZED);
52→
53→        MattermostUserInfoResp userInfoResp = mattermostOAuthFeign.userInfo("Bearer " + accessToken);
54→        String email = userInfoResp.getEmail();
55→
56→        ExceptionUtil.isNotBlank(email, AuthException.UNAUTHORIZED);
57→        log.info("try login use mm:{},{}",email, userInfoResp.getNickname());
58→        return new OAuthUserInfo(email,userInfoResp.getNickname(),accessToken,authTokenResp.getExpiresIn());
59→    }
60→}

