 25→/**
 26→ * OAuth认证模板类，定义了OAuth认证流程中通用的步骤和方法。
 27→ */
 28→@Slf4j
 29→public abstract class AbstractOAuthTemplate implements IOAuthService {
 30→    @Resource
 31→    protected ConstProperties constProperties;
 32→    @Resource
 33→    protected IAuthService authService;
 34→    @Resource
 35→    protected RedisTemplate<String, Object> redisTemplate;
 36→    @Resource
 37→    protected IApitableGrpcClientService apitableGrpcClientService;
 38→    @Resource
 39→    private AffineHttpClientService affineHttpClientService;
 40→
 41→
 42→    /**
 43→     * 获取OAuth服务的简短名称，用来区分要请求的不同服务。
 44→     * 这个名称会用于AuthController里对应方法的service参数。
 45→     * @return 服务名称
 46→     */
 47→    @Override
 48→    public String getServiceName() {
 49→        return getClass().getSimpleName().replace("OAuthServiceImpl", "").toLowerCase();
 50→    }
 51→
 52→    protected String getCallbackPath() {
 53→        return "/api/v1/auth/" + getServiceName() + "/oauth/callback";
 54→    }
 55→
 56→    @Override
 57→    public String authorizeUrl(String redirectUri) {
 58→        String stateUUID = IdUtil.simpleUUID();
 59→        String stateKey = String.format(AUTHORIZED_JUMP_URL, stateUUID);
 60→        // 保存 2 分钟，避免重放攻击
 61→        redisTemplate.opsForValue().set(stateKey, redirectUri, 2, TimeUnit.MINUTES);
 62→        return getOAuthBaseUrl() + "/authorize?response_type=code" +
 63→                "&client_id=" + getClientId() +
 64→                "&redirect_uri=" + constProperties.getServerDomain() + getCallbackPath() +
 65→                "&state=" + stateUUID;
 66→    }
 67→
 68→    @Override
 69→    public String registerAndLogin(String code, String state, ClientOriginInfo origin) {
 70→        String stateKey = String.format(AUTHORIZED_JUMP_URL, state);
 71→        String frontRedirectUrl = (String) redisTemplate.opsForValue().get(stateKey);
 72→        // 产品要求去掉校验
 73→//        ExceptionUtil.isNotBlank(frontRedirectUrl, AuthException.UNAUTHORIZED);
 74→        if (StringUtils.isNoneBlank(stateKey)) {
 75→            redisTemplate.delete(stateKey);
 76→        }
 77→        if (frontRedirectUrl == null) {
 78→            log.warn("Redirect url is null");
 79→            frontRedirectUrl = constProperties.getServerDomain();
 80→        }
 81→
 82→        OAuthUserInfo userInfo = retrieveOAuthUserInfo(code, getClientId(), getClientSecret(),
 83→                constProperties.getServerDomain() + getCallbackPath());
 84→
 85→        handleLoginOrRegister(userInfo);
 86→        return frontRedirectUrl;
 87→    }
 88→
 89→    /**
 90→     * 获取OAuth服务的URL。
 91→     * @return OAuth服务的URL
 92→     */
 93→    protected abstract String getOAuthBaseUrl();
 94→    protected abstract String getClientId();
 95→    protected abstract String getClientSecret();
 96→
 97→    /**
 98→     * 获取用户信息。此方法由子类实现，因为每个OAuth服务的详细实现可能不同。
 99→     * @param code 授权码
100→     * @param clientId 客户端ID
101→     * @param clientSecret 客户端秘钥
102→     * @param redirectUri 重定向URI
103→     * @return OAuthUserInfo 包含用户信息的对象
104→     */
105→    protected abstract OAuthUserInfo retrieveOAuthUserInfo(String code, String clientId, String clientSecret, String redirectUri);
106→
107→    /**
108→     * 处理用户的登录或注册。
109→     * @param userInfo 包含用户邮箱和其他信息的对象
110→     */
111→    protected void handleLoginOrRegister(OAuthUserInfo userInfo) {
112→        String email = userInfo.getEmail();
113→        String nickname = userInfo.getNickname();
114→        ExceptionUtil.isNotBlank(email, AuthException.UNAUTHORIZED);
115→        String accessKey = String.format(ACCESS_TOKEN_EMAIL, email);
116→        redisTemplate.opsForValue().set(accessKey, userInfo.getAccessToken(), userInfo.getExpiresIn(), TimeUnit.SECONDS);
117→        UserSimpleInfoVo userByEmail = apitableGrpcClientService.getUserByEmail(email);
118→        if (userByEmail == null) {
119→            authService.register(email, nickname, RandomExtendUtil.randomString(8), false);
120→        }
121→        authService.ssoLogin(email);
122→    }
123→}

