100→                    );
101→                    success = true; // 调用成功，退出重试循环
102→                } catch (Exception e) {
103→                    retryCount++;
104→                    if (retryCount > 3) {
105→                        // 重试次数用尽，抛出异常
106→                        log.error("获取Mattermost用户列表失败，已重试{}次，最终错误: {}",
107→                                retryCount - 1, e.getMessage());
108→                        throw e;
109→                    }
110→                    // 等待一段时间后重试（指数退避）
111→                    long waitTime = 250L * retryCount; //
112→                    log.warn("第{}次获取用户列表失败，{}ms后重试。错误: {}",
113→                            retryCount, waitTime, e.getMessage());
114→                    try {
115→                        Thread.sleep(waitTime);
116→                    } catch (InterruptedException ie) {
117→                        Thread.currentThread().interrupt();
118→                        throw new RuntimeException("重试被中断", ie);
119→                    }
120→                }
121→            }
122→
123→
124→            if (CollectionUtils.isEmpty(mattermostUsers) || mattermostUsers.size() < batchSize) {
125→                hasMore = false;
126→            }
127→
128→            allUsers.addAll(mattermostUsers);
129→            page++;
130→
131→        }
132→
133→        return allUsers;
134→    }
